mapper.select:
SELECT

FROM contract_info t0

  t0.is_deleted = 0

    AND t0.create_stamp BETWEEN

      #{item}



    AND t0.id in

      #{ids}



    AND (

      t0.follow_up LIKE CONCAT('%',#{item},'%')

    )


    AND t0.id = #{request.id}


    AND t0.follow_up LIKE CONCAT('%',#{request.followUp},'%')


    AND t0.tenant_id = #{request.tenantId}


    AND t0.creator = #{request.creator}


    AND t0.create_stamp = #{request.createStamp}


    AND t0.last_editor = #{request.lastEditor}


    AND t0.last_edit_stamp = #{request.lastEditStamp}


    AND t0.contract_name LIKE CONCAT('%',#{request.contractName},'%')


    AND t0.contract_code LIKE CONCAT('%',#{request.contractCode},'%')


    AND t0.contract_type = #{request.contractType}


    AND t0.contract_money = #{request.contractMoney}


    AND t0.signing_date = #{request.signingDate}


    AND t0.start_date = #{request.startDate}


    AND t0.end_date = #{request.endDate}


    AND t0.contract_abstract = #{request.contractAbstract}


    AND t0.agent_way = #{request.agentWay}


    AND t0.law_firm_id = #{request.lawFirmId}


    AND t0.agency_fee_ratio = #{request.agencyFeeRatio}


    AND t0.is_deleted = #{request.isDeleted}




    ORDER BY ${request.field} ${request.order}


    ORDER BY t0.id DESC
